75	/// Per-lemma verdict. The printed text of a falsified verdict depends on the
76	/// lemma's [`TraceKind`] (see [`LemmaOutcome::result_text`]); verified and
77	/// incomplete verdicts print the same for both kinds.
78	#[derive(Debug, Clone, Copy, PartialEq, Eq)]
79	pub enum LemmaResult {
80	    Verified,
81	    Falsified,
82	    AnalysisIncomplete,
83	}
84	
85	/// One lemma's verdict line in a theory's summary body:
86	/// `<name> (<kind>): <verdict> (<steps> steps)`.
87	#[derive(Debug, Clone)]
88	pub struct LemmaOutcome {
89	    pub name: String,
90	    pub kind: TraceKind,
91	    pub result: LemmaResult,
92	    /// The `<N>` in `(<N> steps)` — the number of proof steps explored (also the
93	    /// value shown for bounded/incomplete analyses, reflecting the explored depth).
94	    pub steps: u64,
95	}
96	
97	impl LemmaOutcome {
98	    /// The verdict phrase. `verified` and `analysis incomplete` are uniform; a
99	    /// `falsified` verdict reads `falsified - found trace` for an all-traces lemma
100	    /// (a counter-example was produced) and `falsified - no trace found` for an
101	    /// exists-trace lemma (no witnessing trace exists).
102	    fn result_text(&self) -> &'static str {
103	        match self.result {
104	            LemmaResult::Verified => "verified",
105	            LemmaResult::AnalysisIncomplete => "analysis incomplete",
106	            LemmaResult::Falsified => match self.kind {
107	                TraceKind::AllTraces => "falsified - found trace",
108	                TraceKind::ExistsTrace => "falsified - no trace found",
109	            },
110	        }
111	    }
112	
113	    /// The single result line, without its `  ` indent.
114	    fn line(&self) -> String {
115	        format!(
116	            "{} ({}): {} ({} steps)",
117	            self.name,
118	            self.kind.text(),
119	            self.result_text(),
120	            self.steps
121	        )
122	    }
123	}
124	
125	/// Prefix shared by the `WARNING:` line and its aligned advisory continuation.
126	const WARNING_PREFIX: &str = "  WARNING: ";
127	
128	/// The wellformedness-warning heading of a theory's summary body. Present only
129	/// when at least one wellformedness check failed.
130	#[derive(Debug, Clone)]
131	pub struct WarningSummary {
132	    /// The `<N>` in `WARNING: <N> wellformedness check failed!` (the noun stays
133	    /// singular "check" regardless of `<N>`).
134	    pub failed_checks: u64,
135	    /// Whether the advisory line `The analysis results might be wrong!` follows
136	    /// the count line. Observed: emitted exactly when the run is a proving run
137	    /// (`--prove`), independent of how many lemmas were actually proved (a
138	    /// proving run with zero matched lemmas still emits it; a plain analyze run
139	    /// never does).
140	    pub analysis_maybe_wrong: bool,
141	}
142	
143	impl WarningSummary {
144	    /// The warning heading (one or two lines, each `\n`-terminated). The advisory
145	    /// continuation is left-padded to align under the text after `WARNING: `.
146	    fn render(&self) -> String {
147	        let mut s = String::new();
148	        s.push_str(WARNING_PREFIX);
149	        s.push_str(&format!("{} wellformedness check failed!\n", self.failed_checks));
150	        if self.analysis_maybe_wrong {
151	            for _ in 0..WARNING_PREFIX.len() {
152	                s.push(' ');
153	            }
154	            s.push_str("The analysis results might be wrong!\n");
155	        }
156	        s
157	    }
158	}
