160	/// One theory's contribution to the "summary of summaries" block.
161	#[derive(Debug, Clone)]
162	pub struct Summary {
163	    /// The `analyzed:` path, echoed exactly as given on the command line.
164	    pub analyzed: String,
165	    /// The `output:` path, present only when the theory was written to a file
166	    /// (`-o`/`-O`).
167	    pub output: Option<String>,
168	    /// Rendered as seconds with two decimals (e.g. `0.39s`).
169	    pub processing_time: f64,
170	    /// The wellformedness-warning heading, when any check failed.
171	    pub warnings: Option<WarningSummary>,
172	    /// The per-lemma verdict lines, in report order.
173	    pub lemmas: Vec<LemmaOutcome>,
174	}
175	
176	impl Summary {
177	    /// The theory's block: the `analyzed:` header, a blank line, the aligned
178	    /// key/value rows (`output:` when present, then `processing time:`), then the
179	    /// body. The body opens with a `  ` (two-space) line and carries up to two
180	    /// sections — the warning heading and the lemma lines, in that order — each
181	    /// section preceded by a `  ` line (so a `  ` line also separates the two when
182	    /// both are present).
183	    fn render_block(&self) -> String {
184	        let mut b = String::new();
185	        b.push_str(&format!("analyzed: {}\n", self.analyzed));
186	        b.push('\n');
187	
188	        // Aligned key/value rows: labels right-padded to the widest label, then a
189	        // single space, so every value starts at the same column.
190	        let mut rows: Vec<(&str, String)> = Vec::new();
191	        if let Some(o) = &self.output {
192	            rows.push(("output:", o.clone()));
193	        }
194	        rows.push(("processing time:", format!("{:.2}s", self.processing_time)));
195	        let width = rows.iter().map(|(label, _)| label.len()).max().unwrap_or(0);
196	        for (label, value) in &rows {
197	            b.push_str("  ");
198	            b.push_str(label);
199	            for _ in 0..(width - label.len()) {
200	                b.push(' ');
201	            }
202	            b.push(' ');
203	            b.push_str(value);
204	            b.push('\n');
205	        }
206	
207	        // Body: an opening `  ` (two-space) line, then the present sections joined
208	        // by another `  ` line — the warning heading first, then the lemma lines.
209	        b.push_str("  \n");
210	        let mut sections: Vec<String> = Vec::new();
211	        if let Some(w) = &self.warnings {
212	            sections.push(w.render());
213	        }
214	        if !self.lemmas.is_empty() {
215	            let mut lines = String::new();
216	            for l in &self.lemmas {
217	                lines.push_str("  ");
218	                lines.push_str(&l.line());
219	                lines.push('\n');
220	            }
221	            sections.push(lines);
222	        }
223	        b.push_str(&sections.join("  \n"));
224	        b
225	    }
226	}
227	
228	/// The full "summary of summaries" section as it appears on stdout: a leading
229	/// blank line (the payload/summary separator, always present), the top `=` rule,
230	/// the header, each theory block preceded by a blank line, a trailing blank line,
231	/// and the bottom rule.
232	pub fn render_summary(summaries: &[Summary]) -> String {
233	    let rule = "=".repeat(RULE_WIDTH);
234	    let mut out = String::new();
235	    out.push('\n');
236	    out.push_str(&rule);
237	    out.push('\n');
238	    out.push_str("summary of summaries:\n");
239	    for s in summaries {
240	        out.push('\n');
241	        out.push_str(&s.render_block());
242	    }
243	    out.push('\n');
244	    out.push_str(&rule);
245	    out.push('\n');
246	    out
247	}
