249	/// A theory processed by a closed batch run.
250	#[derive(Debug, Clone)]
251	pub struct BatchTheory {
252	    /// Name used in the `[Theory <name>]` progress markers (stderr).
253	    pub name: String,
254	    /// The printed theory payload (stdout), or `None` when it was written to an
255	    /// output file instead.
256	    pub payload: Option<String>,
257	    /// Further progress lines the engine emitted for this theory after the five
258	    /// closed phases (stderr), verbatim and newline-terminated. Empty for a plain
259	    /// analyze run; under `--prove` it carries the `[Saturating Sources] …` lines.
260	    pub extra_progress: String,
261	    /// This theory's summary contribution (stdout).
262	    pub summary: Summary,
263	}
264	
265	/// A closed batch run over one or more theories.
266	///
267	/// stderr: the maude preamble, then per theory the five progress markers followed
268	/// by any extra engine progress. stdout: the printed payloads (in order), then one
269	/// combined summary block.
270	pub fn frame_batch(maude: &MaudeInfo, theories: &[BatchTheory]) -> Streams {
271	    let mut s = Streams::default();
272	    s.err.push_str(&maude_preamble(maude));
273	    for t in theories {
274	        s.err.push_str(&progress_block(&t.name, &CLOSED_PHASES));
275	        s.err.push_str(&t.extra_progress);
276	    }
277	    for t in theories {
278	        if let Some(p) = &t.payload {
279	            s.out.push_str(p);
280	        }
281	    }
282	    let summaries: Vec<Summary> = theories.iter().map(|t| t.summary.clone()).collect();
283	    s.out.push_str(&render_summary(&summaries));
284	    s
285	}
286	
287	/// A theory under `--parse-only`: its name (for the single progress marker) and
288	/// its opaque payload.
289	#[derive(Debug, Clone)]
290	pub struct LoadedTheory {
291	    pub name: String,
292	    pub payload: String,
293	}
294	
295	/// A `--parse-only` run: stderr carries one `Theory loaded` marker per theory (no
296	/// preamble); stdout carries the concatenated payloads (no summary block).
297	pub fn frame_parse_only(theories: &[LoadedTheory]) -> Streams {
298	    let mut s = Streams::default();
299	    for t in theories {
300	        s.err.push_str(&progress_line(&t.name, Phase::Loaded));
301	        s.out.push_str(&t.payload);
302	    }
303	    s
304	}
305	
306	/// A `variants` run: stdout carries the variant payload; stderr carries only the
307	/// maude preamble (no progress markers, no summary).
308	pub fn frame_variants(maude: &MaudeInfo, payload: &str) -> Streams {
309	    Streams { out: payload.to_string(), err: maude_preamble(maude) }
310	}
